const updateTitle = handler<{ detail: { value: string } }, { title: string }>(
  ({ detail }, state) => {
    detail?.value && (state.title = detail.value);
  },
);

// Handler to pat a specific kitty
const patKitty = handler<{}, { kitty: KittyCounter }>(({}, { kitty }) => {
  kitty.pats += 1;
});

