const goodbyeKitty = handler<{}, { kitties: KittyCounter[]; kitty: KittyCounter }>(
  ({}, state) => {
    const index = state.kitties.findIndex((k) => k.name === state.kitty.name);
    state.kitties.splice(index, 1);
  },
);

