                  Pat Kitty 🐾
                </button>
                <button 
                  class="goodbye-button"
                  onclick={goodbyeKitty({ kitty, kitties })}
                >
                  Goodbye Kitty 😢
                </button>
              </li>
            ))}
          </ul>,
          <p><em>No kitties yet! Time to adopt some!</em></p>
