            onclick={adoptKitty({ kitties })}
          >
            Adopt A Kitty 😺
          </button>

          <button 
            class="random-pat-button"
            onclick={patRandomKitty({ kitties })}
          >
            Pat Random Kitty 🎲
          </button>
        </div>

        <p class="total-pats">
          Total Pats Given: <span id="total">{totalPats}</span>
        </p>
      </os-container>
    ),
  };
});

